130: void GrpcHealthCheckerImpl::GrpcActiveHealthCheckSession::decodeData(Buffer::Instance& data,
131:                                                                      bool end_stream) {
132:   if (end_stream) {
133:     onRpcComplete(Grpc::Status::WellKnownGrpcStatus::Internal,
134:                   "gRPC protocol violation: unexpected stream end", true);
135:     return;
136:   }
137:   // We should end up with only one frame here.
138:   std::vector<Grpc::Frame> decoded_frames;
139:   if (!decoder_.decode(data, decoded_frames).ok()) {
140:     onRpcComplete(Grpc::Status::WellKnownGrpcStatus::Internal, "gRPC wire protocol decode error",
141:                   false);
142:     return;
143:   }
144:   for (auto& frame : decoded_frames) {
145:     if (frame.length_ > 0) {
146:       if (health_check_response_) {
147:         // grpc.health.v1.Health.Check is unary RPC, so only one message is allowed.
148:         onRpcComplete(Grpc::Status::WellKnownGrpcStatus::Internal, "unexpected streaming", false);
149:         return;
150:       }
151:       health_check_response_ = std::make_unique<grpc::health::v1::HealthCheckResponse>();
152:       Buffer::ZeroCopyInputStreamImpl stream(std::move(frame.data_));
153: 
154:       if (frame.flags_ != Grpc::GRPC_FH_DEFAULT ||
155:           !health_check_response_->ParseFromZeroCopyStream(&stream)) {
156:         onRpcComplete(Grpc::Status::WellKnownGrpcStatus::Internal,
157:                       "invalid grpc.health.v1 RPC payload", false);
158:         return;
159:       }
160:     }
161:   }
162: }
